var e=[{slug:"gebrauchtes-fahrrad-kaufen-tipps",coverImage:"assets/blog/gebrauchtes-fahrrad.jpg",date:"2026-04-12",readingTime:8,category:"ratgeber",tags:["gebrauchtes fahrrad","kaufen","tipps","checkliste"],relatedSlugs:["welches-fahrrad-passt-zu-mir","e-bike-gebraucht-kaufen"],translations:{de:{title:"Gebrauchtes Fahrrad kaufen \u2014 Worauf achten?",metaTitle:"Gebrauchtes Fahrrad kaufen \u2014 Tipps & Checkliste | Karaarslan Bike",metaDescription:"Gebrauchtes Fahrrad kaufen ohne Risiko. Erfahren Sie, worauf Sie bei Rahmen, Bremsen, Schaltung & Reifen achten m\xFCssen. Checkliste vom Fachh\xE4ndler.",excerpt:"Ein gebrauchtes Fahrrad kann ein Schn\xE4ppchen sein \u2014 oder eine Entt\xE4uschung. Mit unserer Checkliste kaufen Sie sicher.",tldr:"Achten Sie auf Rahmen, Bremsen, Schaltung, Reifen und Lager. Kaufen Sie beim Fachh\xE4ndler mit Garantie statt privat. Bei Karaarslan Bike gibt es gepr\xFCfte Gebrauchtr\xE4der mit 3 Monaten Garantie.",sections:[{type:"heading",content:"Warum ein gebrauchtes Fahrrad kaufen?"},{type:"paragraph",content:"Ein gebrauchtes Fahrrad ist nachhaltig, preiswert und sofort verf\xFCgbar. Bei einem seri\xF6sen H\xE4ndler wie Karaarslan Bike bekommen Sie gepr\xFCfte R\xE4der mit Garantie \u2014 das ist der gr\xF6\xDFte Vorteil gegen\xFCber Privatverk\xE4ufen auf Kleinanzeigen."},{type:"heading",content:"Checkliste: Darauf sollten Sie achten"},{type:"list",items:["Rahmen: Auf Risse, Dellen und Rost pr\xFCfen. Ein verbogener Rahmen ist ein Ausschlusskriterium.","Bremsen: Beide Bremsen m\xFCssen fest zupacken. Bremsbel\xE4ge d\xFCrfen nicht abgefahren sein.","Schaltung: Alle G\xE4nge durchschalten. Kette und Zahnkr\xE4nze auf Verschlei\xDF pr\xFCfen.","Reifen: Profil und Seitenw\xE4nde kontrollieren. Risse = sofort wechseln.","Lager: Tretlager, Steuersatz und Naben d\xFCrfen kein Spiel haben.","Licht: Dynamo oder Akku-Beleuchtung muss funktionieren (StVZO-Pflicht).","Rahmennummer: Jedes legale Fahrrad hat eine eingestanzte Rahmennummer."]},{type:"tip",content:"Bei Karaarslan Bike wird jedes Gebrauchtrad technisch gepr\xFCft und mit 3 Monaten Garantie verkauft. Sie k\xF6nnen jedes Fahrrad vor Ort probefahren \u2014 kein Termin n\xF6tig."},{type:"heading",content:"Gebraucht vs. Neu \u2014 Was lohnt sich mehr?"},{type:"paragraph",content:'F\xFCr Alltagsfahrer und Pendler ist ein gebrauchtes Fahrrad oft die bessere Wahl: Sie sparen 30\u201360 % gegen\xFCber dem Neupreis und bekommen ein hochwertiges Rad, das bereits "eingefahren" ist. F\xFCr sportliche Anspr\xFCche oder E-Bikes lohnt sich ein Neukauf h\xE4ufiger, da Akku- und Motorgarantie wichtig sind.'},{type:"heading",content:"Wo gebrauchte Fahrr\xE4der in [SEHIR] kaufen?"},{type:"paragraph",content:"Karaarslan Bike in der [ADRES] bietet \xFCber 100 gepr\xFCfte neue und gebrauchte Fahrr\xE4der. Alle R\xE4der haben Garantie und k\xF6nnen vor Ort probegefahren werden. Wir sind Mo\u2013Fr 10\u201318 Uhr und Sa 10\u201314 Uhr f\xFCr Sie da."},{type:"cta",content:"Jetzt Showroom entdecken",link:"/showroom",linkText:"Zum Showroom"}]},en:{title:"Buying a Used Bike \u2014 What to Look For",metaTitle:"Buying a Used Bike \u2014 Tips & Checklist | Karaarslan Bike",metaDescription:"Buy a used bike without risk. Learn what to check \u2014 frame, brakes, gears & tires. Expert checklist from your [SEHIR] bike shop.",excerpt:"A used bicycle can be a great deal \u2014 or a disappointment. Use our checklist to buy safely.",tldr:"Check frame, brakes, gears, tires and bearings. Buy from a dealer with warranty instead of privately. At Karaarslan Bike you get inspected used bikes with a 3-month warranty.",sections:[{type:"heading",content:"Why buy a used bicycle?"},{type:"paragraph",content:"A used bike is sustainable, affordable and available right away. At a trusted dealer like Karaarslan Bike you get inspected bikes with warranty \u2014 the biggest advantage over private sales."},{type:"heading",content:"Checklist: What to look for"},{type:"list",items:["Frame: Check for cracks, dents and rust. A bent frame is a deal-breaker.","Brakes: Both brakes must grip firmly. Worn brake pads need replacing.","Gears: Shift through all gears. Check chain and sprockets for wear.","Tires: Inspect tread and sidewalls. Cracks mean immediate replacement.","Bearings: Bottom bracket, headset and hubs must have no play.","Lights: Dynamo or battery lighting must work (legally required in Germany).","Frame number: Every legal bike has a stamped frame number."]},{type:"tip",content:"At Karaarslan Bike every used bike is technically inspected and sold with a 3-month warranty. Test ride any bike on site \u2014 no appointment needed."},{type:"cta",content:"Explore our showroom",link:"/showroom",linkText:"Visit Showroom"}]},fr:{title:"Acheter un v\xE9lo d'occasion \u2014 \xC0 quoi faire attention ?",metaTitle:"Acheter un v\xE9lo d'occasion \u2014 Conseils | Karaarslan Bike",metaDescription:"Achetez un v\xE9lo d'occasion sans risque. D\xE9couvrez ce qu'il faut v\xE9rifier \u2014 cadre, freins, vitesses & pneus.",excerpt:"Un v\xE9lo d'occasion peut \xEAtre une bonne affaire \u2014 ou une d\xE9ception. Suivez notre checklist.",tldr:"V\xE9rifiez le cadre, les freins, les vitesses et les pneus. Achetez chez un professionnel avec garantie. Chez Karaarslan Bike : v\xE9los contr\xF4l\xE9s avec 3 mois de garantie.",sections:[{type:"heading",content:"Pourquoi acheter un v\xE9lo d'occasion ?"},{type:"paragraph",content:"Un v\xE9lo d'occasion est durable, abordable et disponible imm\xE9diatement. Chez Karaarslan Bike, chaque v\xE9lo est contr\xF4l\xE9 et vendu avec garantie."},{type:"cta",content:"D\xE9couvrir le showroom",link:"/showroom",linkText:"Voir le Showroom"}]},tr:{title:"\u0130kinci El Bisiklet Al\u0131rken Nelere Dikkat Etmeli?",metaTitle:"\u0130kinci El Bisiklet Alma Rehberi | Karaarslan Bike",metaDescription:"\u0130kinci el bisiklet al\u0131rken nelere dikkat etmelisiniz? Kadro, fren, vites ve lastik kontrol listesi.",excerpt:"\u0130kinci el bisiklet hem uygun fiyatl\u0131 hem s\xFCrd\xFCr\xFClebilir olabilir \u2014 do\u011Fru kontrolle.",tldr:"Kadro, fren, vites, lastik ve yataklara dikkat edin. Garantili sat\u0131c\u0131dan al\u0131n. Karaarslan Bike'da kontroll\xFC bisikletler 3 ay garantiyle sat\u0131l\u0131r.",sections:[{type:"heading",content:"Neden ikinci el bisiklet?"},{type:"paragraph",content:"\u0130kinci el bisiklet s\xFCrd\xFCr\xFClebilir, uygun fiyatl\u0131 ve hemen kullan\u0131ma haz\u0131rd\u0131r. Karaarslan Bike'da her bisiklet teknik kontrolden ge\xE7er ve 3 ay garantiyle sat\u0131l\u0131r."},{type:"cta",content:"Showroom'u ke\u015Ffedin",link:"/showroom",linkText:"Showroom'a Git"}]}}},{slug:"welches-fahrrad-passt-zu-mir",coverImage:"assets/blog/welches-fahrrad.jpg",date:"2026-04-12",readingTime:10,category:"ratgeber",tags:["fahrradtyp","beratung","citybike","trekking","mountainbike"],relatedSlugs:["fahrrad-rahmengroesse-berechnen","gebrauchtes-fahrrad-kaufen-tipps"],translations:{de:{title:"Welches Fahrrad passt zu mir? \u2014 Der gro\xDFe Ratgeber",metaTitle:"Welches Fahrrad passt zu mir? Ratgeber 2026 | Karaarslan Bike",metaDescription:"Citybike, Trekkingrad, Mountainbike oder E-Bike? Finden Sie heraus, welcher Fahrradtyp zu Ihrem Fahrstil passt. Kostenlose Beratung in [SEHIR].",excerpt:"City, Trekking, Mountain oder E-Bike? Wir helfen Ihnen, den richtigen Fahrradtyp f\xFCr Ihren Alltag zu finden.",tldr:"Kurze Stadtstrecken \u2192 Citybike. Pendeln \u2192 Trekkingrad. Lange Strecken \u2192 E-Bike. Sport & Gel\xE4nde \u2192 Mountainbike. Kostenlose Beratung bei Karaarslan Bike.",sections:[{type:"heading",content:"Fahrradtypen im \xDCberblick"},{type:"paragraph",content:"Die Wahl des richtigen Fahrrads h\xE4ngt von drei Faktoren ab: Wo fahren Sie? Wie weit fahren Sie? Und wie sportlich m\xF6chten Sie unterwegs sein? Hier ein \xDCberblick \xFCber die wichtigsten Fahrradtypen."},{type:"heading",content:"Citybike \u2014 Der Alltagsheld"},{type:"paragraph",content:"Ideal f\xFCr den t\xE4glichen Weg zur Arbeit, zum Einkaufen oder f\xFCr kurze Strecken in der Stadt. Citybikes haben einen bequemen, aufrechten Sitz, Schutzbleche, Gep\xE4cktr\xE4ger und Licht. In [SEHIR] die beliebteste Wahl f\xFCr Pendler und Studenten."},{type:"heading",content:"Trekkingrad \u2014 Der Allrounder"},{type:"paragraph",content:"Das Trekkingrad vereint Komfort und Sportlichkeit. Perfekt f\xFCr l\xE4ngere Touren, Radwege und leichtes Gel\xE4nde. Mit Gep\xE4cktr\xE4ger und Beleuchtung auch alltagstauglich. Die beste Wahl, wenn Sie ein Fahrrad f\xFCr alles suchen."},{type:"heading",content:"Mountainbike \u2014 F\xFCr Gel\xE4nde & Sport"},{type:"paragraph",content:"Breite Reifen, Federung und robuster Rahmen \u2014 Mountainbikes sind f\xFCr Waldwege, Trails und sportliches Fahren gemacht. Im Schwarzwald rund um [SEHIR] gibt es unz\xE4hlige Trails."},{type:"heading",content:"E-Bike \u2014 Elektrisch unterst\xFCtzt"},{type:"paragraph",content:"Ein E-Bike (Pedelec) unterst\xFCtzt Sie mit einem Elektromotor bis 25 km/h. Ideal f\xFCr Pendler mit langen Strecken, Berge oder wenn Sie einfach entspannter ankommen m\xF6chten. In [SEHIR] mit seinen Steigungen besonders beliebt."},{type:"heading",content:"Unsere Empfehlung"},{type:"list",items:["Kurze Stadtstrecken (< 5 km): Citybike oder Hollandrad","Pendeln (5\u201315 km): Trekkingrad oder Citybike","Lange Strecken (> 15 km): E-Bike oder Trekkingrad","Sport & Gel\xE4nde: Mountainbike","Mit Kindern: Kindersitz-kompatibles Citybike oder Lastenrad"]},{type:"tip",content:"Unsicher? Kommen Sie einfach bei Karaarslan Bike vorbei. Wir beraten Sie kostenlos und Sie k\xF6nnen verschiedene R\xE4der probefahren. [ADRES], Mo\u2013Fr 10\u201318 Uhr."},{type:"cta",content:"Jetzt Fahrr\xE4der ansehen",link:"/showroom",linkText:"Zum Showroom"}]},en:{title:"Which Bike is Right for Me? \u2014 Complete Guide",metaTitle:"Which Bike is Right for Me? Guide 2026 | Karaarslan Bike",metaDescription:"City bike, trekking, mountain or e-bike? Find out which type suits your riding style. Free advice in [SEHIR].",excerpt:"City, trekking, mountain or e-bike? We help you find the right bike type.",tldr:"Short city trips \u2192 city bike. Commuting \u2192 trekking bike. Long distances \u2192 e-bike. Sport & trails \u2192 mountain bike. Free advice at Karaarslan Bike.",sections:[{type:"heading",content:"Bike types at a glance"},{type:"paragraph",content:"Choosing the right bike depends on three things: where you ride, how far, and how sporty you want to be."},{type:"cta",content:"Browse our bikes",link:"/showroom",linkText:"Visit Showroom"}]},fr:{title:"Quel v\xE9lo me convient ? \u2014 Guide complet",metaTitle:"Quel v\xE9lo me convient ? Guide 2026 | Karaarslan Bike",metaDescription:"V\xE9lo de ville, trekking, VTT ou VAE ? Trouvez le type de v\xE9lo adapt\xE9 \xE0 votre style.",excerpt:"Ville, trekking, VTT ou VAE ? Nous vous aidons \xE0 choisir.",tldr:"Trajets courts \u2192 v\xE9lo de ville. Trajets quotidiens \u2192 trekking. Longues distances \u2192 VAE. Sport \u2192 VTT. Conseils gratuits chez Karaarslan Bike.",sections:[{type:"heading",content:"Types de v\xE9los en un coup d'\u0153il"},{type:"paragraph",content:"Le choix du bon v\xE9lo d\xE9pend de trois facteurs : o\xF9 roulez-vous, quelle distance, et quel niveau sportif recherchez-vous."},{type:"cta",content:"Voir nos v\xE9los",link:"/showroom",linkText:"Showroom"}]},tr:{title:"Bana Hangi Bisiklet Uygun? \u2014 Kapsaml\u0131 Rehber",metaTitle:"Bana Hangi Bisiklet Uygun? 2026 Rehberi | Karaarslan Bike",metaDescription:"\u015Eehir, trekking, da\u011F veya elektrikli bisiklet? S\xFCr\xFC\u015F tarz\u0131n\u0131za uygun tipi bulun.",excerpt:"\u015Eehir, trekking, da\u011F veya e-bisiklet? Size uygun tipi bulman\u0131za yard\u0131mc\u0131 olal\u0131m.",tldr:"K\u0131sa \u015Fehir i\xE7i \u2192 \u015Fehir bisikleti. \u0130\u015Fe gidi\u015F \u2192 trekking. Uzun mesafe \u2192 e-bisiklet. Spor & arazi \u2192 da\u011F bisikleti. Karaarslan Bike'da \xFCcretsiz dan\u0131\u015Fmanl\u0131k.",sections:[{type:"heading",content:"Bisiklet tipleri bir bak\u0131\u015Fta"},{type:"paragraph",content:"Do\u011Fru bisikleti se\xE7mek \xFC\xE7 fakt\xF6re ba\u011Fl\u0131d\u0131r: nerede s\xFCr\xFCyorsunuz, ne kadar uzak, ne kadar sportif olmak istiyorsunuz."},{type:"cta",content:"Bisikletlere g\xF6z at\u0131n",link:"/showroom",linkText:"Showroom'a Git"}]}}},{slug:"fahrrad-rahmengroesse-berechnen",coverImage:"assets/blog/rahmengroesse.jpg",date:"2026-04-12",readingTime:6,category:"ratgeber",tags:["rahmengr\xF6\xDFe","berechnen","tabelle","schrittl\xE4nge"],relatedSlugs:["welches-fahrrad-passt-zu-mir","gebrauchtes-fahrrad-kaufen-tipps"],translations:{de:{title:"Fahrrad Rahmengr\xF6\xDFe berechnen \u2014 Tabelle & Anleitung",metaTitle:"Fahrrad Rahmengr\xF6\xDFe berechnen \u2014 Tabelle 2026 | Karaarslan Bike",metaDescription:"Fahrrad Rahmengr\xF6\xDFe berechnen: Schrittl\xE4nge messen, Formel anwenden, richtige Gr\xF6\xDFe finden. Mit Tabelle f\xFCr City, Trekking, MTB & E-Bike.",excerpt:"Die richtige Rahmengr\xF6\xDFe ist entscheidend f\xFCr Komfort und Sicherheit. So berechnen Sie Ihre optimale Rahmenh\xF6he.",tldr:"Schrittl\xE4nge messen und mit dem Faktor multiplizieren: City/Trekking \xD70,66, MTB \xD70,574, Rennrad \xD70,665. Zwischen zwei Gr\xF6\xDFen? Sportlich \u2192 kleiner, komfortabel \u2192 gr\xF6\xDFer.",sections:[{type:"heading",content:"Warum die richtige Rahmengr\xF6\xDFe wichtig ist"},{type:"paragraph",content:"Ein zu gro\xDFer oder zu kleiner Rahmen f\xFChrt zu R\xFCcken-, Knie- und Nackenschmerzen. Die richtige Rahmengr\xF6\xDFe sorgt f\xFCr eine ergonomische Sitzposition und mehr Spa\xDF beim Fahren."},{type:"heading",content:"Schritt 1: Schrittl\xE4nge messen"},{type:"paragraph",content:"Stellen Sie sich barfu\xDF mit dem R\xFCcken an eine Wand. Klemmen Sie ein Buch waagerecht zwischen Ihre Beine (wie ein Sattel). Messen Sie den Abstand vom Boden bis zur Oberkante des Buches \u2014 das ist Ihre Schrittl\xE4nge in cm."},{type:"heading",content:"Schritt 2: Rahmengr\xF6\xDFe berechnen"},{type:"list",items:["Citybike / Hollandrad: Schrittl\xE4nge \xD7 0,66 = Rahmenh\xF6he (cm)","Trekkingrad: Schrittl\xE4nge \xD7 0,66 = Rahmenh\xF6he (cm)","Mountainbike: Schrittl\xE4nge \xD7 0,574 = Rahmenh\xF6he (cm)","Rennrad: Schrittl\xE4nge \xD7 0,665 = Rahmenh\xF6he (cm)","E-Bike: Schrittl\xE4nge \xD7 0,66 = Rahmenh\xF6he (cm)"]},{type:"heading",content:"Rahmengr\xF6\xDFe Tabelle (\xDCbersicht)"},{type:"list",items:["K\xF6rpergr\xF6\xDFe 155\u2013165 cm \u2192 Rahmenh\xF6he 42\u201347 cm (City/Trekking)","K\xF6rpergr\xF6\xDFe 165\u2013175 cm \u2192 Rahmenh\xF6he 47\u201352 cm (City/Trekking)","K\xF6rpergr\xF6\xDFe 175\u2013185 cm \u2192 Rahmenh\xF6he 52\u201356 cm (City/Trekking)","K\xF6rpergr\xF6\xDFe 185\u2013195 cm \u2192 Rahmenh\xF6he 56\u201361 cm (City/Trekking)","K\xF6rpergr\xF6\xDFe 195+ cm \u2192 Rahmenh\xF6he 61+ cm (City/Trekking)"]},{type:"tip",content:"Zwischen zwei Gr\xF6\xDFen? W\xE4hlen Sie die kleinere Gr\xF6\xDFe, wenn Sie sportlich fahren, und die gr\xF6\xDFere f\xFCr komfortables Fahren. Bei Karaarslan Bike beraten wir Sie gerne pers\xF6nlich."},{type:"cta",content:"Pers\xF6nliche Beratung",link:"/contact",linkText:"Kontakt aufnehmen"}]},en:{title:"Calculate Bike Frame Size \u2014 Table & Guide",metaTitle:"Bike Frame Size Calculator \u2014 Table 2026 | Karaarslan Bike",metaDescription:"Calculate your bike frame size: measure inseam, apply formula, find the right size. Tables for city, trekking, MTB & e-bike.",excerpt:"The right frame size is key to comfort and safety. Here is how to calculate yours.",tldr:"Measure inseam and multiply: City/Trekking \xD70.66, MTB \xD70.574, Road \xD70.665. Between sizes? Sporty \u2192 smaller, comfortable \u2192 larger.",sections:[{type:"heading",content:"Why frame size matters"},{type:"paragraph",content:"An incorrectly sized frame causes back, knee and neck pain. The right size means ergonomic posture and more fun riding."},{type:"cta",content:"Get personal advice",link:"/contact",linkText:"Contact Us"}]},fr:{title:"Calculer la taille du cadre \u2014 Tableau & Guide",metaTitle:"Calculer la taille du cadre v\xE9lo \u2014 Tableau 2026 | Karaarslan Bike",metaDescription:"Calculez votre taille de cadre : mesurez votre entrejambe, appliquez la formule.",excerpt:"La bonne taille de cadre est la cl\xE9 du confort. Voici comment la calculer.",tldr:"Mesurez votre entrejambe et multipliez : Ville/Trekking \xD70,66, VTT \xD70,574, Route \xD70,665. Entre deux tailles ? Sportif \u2192 plus petit, confort \u2192 plus grand.",sections:[{type:"heading",content:"Pourquoi la taille du cadre est importante"},{type:"paragraph",content:"Un cadre mal dimensionn\xE9 provoque des douleurs au dos, aux genoux et au cou."},{type:"cta",content:"Conseils personnalis\xE9s",link:"/contact",linkText:"Contactez-nous"}]},tr:{title:"Bisiklet Kadro Boyu Hesaplama \u2014 Tablo & Rehber",metaTitle:"Bisiklet Kadro Boyu Hesaplama | Karaarslan Bike",metaDescription:"Bisiklet kadro boyunuzu hesaplay\u0131n: bacak i\xE7i \xF6l\xE7\xFCm\xFC, form\xFCl ve tablo.",excerpt:"Do\u011Fru kadro boyu konfor ve g\xFCvenlik i\xE7in \xE7ok \xF6nemlidir.",tldr:"Bacak i\xE7i \xF6l\xE7\xFCs\xFCn\xFC \xE7arp\u0131n: \u015Eehir/Trekking \xD70,66, MTB \xD70,574, Yol \xD70,665. \u0130ki beden aras\u0131ndaysan\u0131z: sportif \u2192 k\xFC\xE7\xFCk, konforlu \u2192 b\xFCy\xFCk.",sections:[{type:"heading",content:"Kadro boyu neden \xF6nemli?"},{type:"paragraph",content:"Yanl\u0131\u015F boyutta kadro s\u0131rt, diz ve boyun a\u011Fr\u0131lar\u0131na neden olur."},{type:"cta",content:"Ki\u015Fisel dan\u0131\u015Fmanl\u0131k",link:"/contact",linkText:"\u0130leti\u015Fim"}]}}},{slug:"e-bike-gebraucht-kaufen",coverImage:"assets/blog/ebike-gebraucht.jpg",date:"2026-04-12",readingTime:7,category:"ratgeber",tags:["e-bike","gebraucht","akku","motor","garantie"],relatedSlugs:["gebrauchtes-fahrrad-kaufen-tipps","welches-fahrrad-passt-zu-mir"],translations:{de:{title:"E-Bike gebraucht kaufen \u2014 Akku, Motor, Garantie",metaTitle:"E-Bike gebraucht kaufen \u2014 Worauf achten? | Karaarslan Bike",metaDescription:"Gebrauchtes E-Bike kaufen: Akku-Zustand, Motor-Check, Garantie. Was Sie beim Kauf eines gebrauchten Pedelecs wissen m\xFCssen.",excerpt:"Ein gebrauchtes E-Bike kann \xFCber 1.000 \u20AC sparen. Worauf Sie bei Akku, Motor und Garantie achten sollten.",tldr:"Ein gutes gebrauchtes E-Bike kostet 800\u20131.500 \u20AC (50 % Ersparnis). Achten Sie auf Akku-Restkapazit\xE4t (mind. 70 %), Ladezyklen und Motor-Zustand. Bei Karaarslan Bike: gepr\xFCfte E-Bikes mit dokumentiertem Akku-Zustand.",sections:[{type:"heading",content:"Lohnt sich ein gebrauchtes E-Bike?"},{type:"paragraph",content:"Neue E-Bikes kosten oft 2.000\u20135.000 \u20AC. Ein gutes gebrauchtes E-Bike bekommen Sie ab 800\u20131.500 \u20AC \u2014 das bedeutet eine Ersparnis von 50 % und mehr. Wichtig ist, dass Akku und Motor in gutem Zustand sind."},{type:"heading",content:"Akku-Check: Das Herzst\xFCck des E-Bikes"},{type:"list",items:["Akku-Kapazit\xE4t: Neue Akkus haben 400\u2013750 Wh. Ein guter gebrauchter Akku hat mindestens 70 % Restkapazit\xE4t.","Ladezyklen: Ein E-Bike-Akku h\xE4lt ca. 500\u20131.000 Ladezyklen. Fragen Sie nach der Anzahl.","Alter: Akkus altern auch ohne Nutzung. Ab 4\u20135 Jahren nimmt die Kapazit\xE4t merklich ab.","Optischer Zustand: Keine Dellen, keine Korrosion an den Kontakten.","Reichweite testen: Probefahrt mit vollem Akku \u2014 mindestens 40 km sollten drin sein."]},{type:"heading",content:"Motor-Check"},{type:"paragraph",content:"Achten Sie w\xE4hrend der Probefahrt auf: gleichm\xE4\xDFige Unterst\xFCtzung ohne Ruckeln, sauberes Ein- und Abschalten bei 25 km/h, keine ungew\xF6hnlichen Ger\xE4usche. Marken wie Bosch, Shimano und Brose gelten als besonders langlebig."},{type:"tip",content:"Bei Karaarslan Bike werden alle gebrauchten E-Bikes technisch gepr\xFCft und der Akku-Zustand dokumentiert. So kaufen Sie ohne b\xF6se \xDCberraschungen."},{type:"cta",content:"E-Bikes im Showroom",link:"/showroom",linkText:"E-Bikes ansehen"}]},en:{title:"Buying a Used E-Bike \u2014 Battery, Motor, Warranty",metaTitle:"Buying a Used E-Bike \u2014 What to Check | Karaarslan Bike",metaDescription:"Used e-bike buying guide: battery health, motor check, warranty. What you need to know before buying a used pedelec.",excerpt:"A used e-bike can save over \u20AC1,000. What to check regarding battery, motor and warranty.",tldr:"A good used e-bike costs \u20AC800\u20131,500 (50% savings). Check battery capacity (min. 70%), charge cycles and motor condition. At Karaarslan Bike: inspected e-bikes with documented battery health.",sections:[{type:"heading",content:"Is a used e-bike worth it?"},{type:"paragraph",content:"New e-bikes cost \u20AC2,000\u20135,000. A good used e-bike starts at \u20AC800\u20131,500 \u2014 saving 50% or more."},{type:"cta",content:"View e-bikes",link:"/showroom",linkText:"Visit Showroom"}]},fr:{title:"Acheter un VAE d'occasion \u2014 Batterie, Moteur, Garantie",metaTitle:"VAE d'occasion \u2014 Que v\xE9rifier ? | Karaarslan Bike",metaDescription:"Guide d'achat VAE d'occasion : \xE9tat de la batterie, v\xE9rification du moteur, garantie.",excerpt:"Un VAE d'occasion permet d'\xE9conomiser plus de 1 000 \u20AC.",tldr:"Un bon VAE d'occasion co\xFBte 800\u20131 500 \u20AC (50 % d'\xE9conomie). V\xE9rifiez la capacit\xE9 batterie (min. 70 %), les cycles de charge et le moteur.",sections:[{type:"heading",content:"Un VAE d'occasion, \xE7a vaut le coup ?"},{type:"paragraph",content:"Les VAE neufs co\xFBtent entre 2 000 et 5 000 \u20AC. Un bon VAE d'occasion commence \xE0 800\u20131 500 \u20AC."},{type:"cta",content:"Voir les VAE",link:"/showroom",linkText:"Showroom"}]},tr:{title:"\u0130kinci El E-Bisiklet Alma Rehberi \u2014 Ak\xFC, Motor, Garanti",metaTitle:"\u0130kinci El E-Bisiklet Al\u0131rken Nelere Dikkat Etmeli? | Karaarslan Bike",metaDescription:"\u0130kinci el e-bisiklet al\u0131rken ak\xFC durumu, motor kontrol\xFC ve garanti hakk\u0131nda bilmeniz gerekenler.",excerpt:"\u0130kinci el e-bisiklet 1.000 \u20AC'dan fazla tasarruf sa\u011Flayabilir.",tldr:"\u0130yi bir ikinci el e-bisiklet 800\u20131.500 \u20AC (% 50 tasarruf). Ak\xFC kapasitesi (min. %70), \u015Farj d\xF6ng\xFCs\xFC ve motor durumuna dikkat edin.",sections:[{type:"heading",content:"\u0130kinci el e-bisiklet al\u0131n\u0131r m\u0131?"},{type:"paragraph",content:"Yeni e-bisikletler 2.000\u20135.000 \u20AC aras\u0131. \u0130yi bir ikinci el e-bisiklet 800\u20131.500 \u20AC'dan ba\u015Flar."},{type:"cta",content:"E-bisikletlere g\xF6z at",link:"/showroom",linkText:"Showroom'a Git"}]}}},{slug:"fahrradladen-[SEHIR]",coverImage:"assets/blog/fahrradladen-[SEHIR].jpg",date:"2026-04-12",readingTime:5,category:"lokal",tags:["fahrradladen","[SEHIR]","fahrradgesch\xE4ft","fahrradh\xE4ndler","bike shop"],relatedSlugs:["gebrauchtes-fahrrad-kaufen-tipps","welches-fahrrad-passt-zu-mir"],translations:{de:{title:"Karaarslan Bike \u2014 Karaarslan Bike",metaTitle:"Karaarslan Bike \u2014 Ihr Fahrradgesch\xE4ft | Karaarslan Bike",metaDescription:"Fahrradladen in [SEHIR] gesucht? Karaarslan Bike: \xDCber 100 neue & gebrauchte Fahrr\xE4der, E-Bikes, Garantie, Probefahrt. [ADRES].",excerpt:"Ihr Fahrradladen in [SEHIR]: Karaarslan Bike bietet \xFCber 100 neue und gebrauchte Fahrr\xE4der mit Garantie.",tldr:"Karaarslan Bike: [ADRES], [PLZ] [SEHIR]. \xDCber 100 neue & gebrauchte Fahrr\xE4der, E-Bikes, Garantie. Mo\u2013Fr 10\u201318, Sa 10\u201314 Uhr. WhatsApp: [TELEFON].",sections:[{type:"heading",content:"Karaarslan Bike \u2014 Ihr Fahrradh\xE4ndler"},{type:"paragraph",content:"Karaarslan Bike ist ein Fahrradgesch\xE4ft in der [ADRES], [PLZ] [SEHIR]. Wir bieten neue und gebrauchte Fahrr\xE4der \u2014 darunter Citybikes, Trekkingr\xE4der, Mountainbikes, E-Bikes, Kinderfahrr\xE4der und Hollandr\xE4der."},{type:"heading",content:"Warum Karaarslan Bike?"},{type:"list",items:["\xDCber 100 Fahrr\xE4der vorr\xE4tig \u2014 keine Wartezeit","Gepr\xFCfte Gebrauchtr\xE4der mit 3 Monaten Garantie","Neue Fahrr\xE4der mit 24 Monaten Garantie","Probefahrt vor Ort \u2014 kein Termin n\xF6tig","Faire, transparente Preise","Beratung auf Deutsch, Englisch und T\xFCrkisch","Zentral gelegen \u2014 auch erreichbar aus Emmendingen, Bad Krozingen, Breisach"]},{type:"heading",content:"\xD6ffnungszeiten & Kontakt"},{type:"list",items:["Mo, Di, Do: 11:00 \u2013 17:30 Uhr","Mittwoch: 14:00 \u2013 17:30 Uhr","Freitag: 11:00 \u2013 13:00 & 15:00 \u2013 18:00 Uhr","Samstag: 11:30 \u2013 17:00 Uhr","Sonn- und feiertags geschlossen","WhatsApp: [TELEFON]","E-Mail: karaarslan-bike.de@gmail.com"]},{type:"heading",content:"So finden Sie uns"},{type:"paragraph",content:"Karaarslan Bike befindet sich in der [ADRES], im Stadtteil Haslach. Gut erreichbar mit dem Auto (Parkpl\xE4tze vorhanden) oder mit der Stra\xDFenbahn. Aus Emmendingen, Bad Krozingen, Breisach, March und Gundelfingen sind wir in 15\u201325 Minuten erreichbar."},{type:"cta",content:"Besuchen Sie uns",link:"/contact",linkText:"Anfahrt & Kontakt"}]},en:{title:"Bike Shop [SEHIR] \u2014 Karaarslan Bike",metaTitle:"Bike Shop [SEHIR] \u2014 Your Bike Store | Karaarslan Bike",metaDescription:"Looking for a bike shop in [SEHIR]? Karaarslan Bike: 100+ new & used bikes, e-bikes, warranty, test rides.",excerpt:"Your bike shop in [SEHIR]: Over 100 new and used bikes with warranty.",tldr:"Karaarslan Bike: [ADRES], [PLZ] [SEHIR]. 100+ new & used bikes, e-bikes, warranty. Mon\u2013Fri 10\u201318, Sat 10\u201314. WhatsApp: [TELEFON].",sections:[{type:"heading",content:"Karaarslan Bike \u2014 Your bike dealer in [SEHIR]"},{type:"paragraph",content:"Karaarslan Bike is a bike shop at [ADRES], [PLZ] [SEHIR]. We offer new and used bikes with warranty."},{type:"cta",content:"Visit us",link:"/contact",linkText:"Directions & Contact"}]},fr:{title:"Magasin de v\xE9los [SEHIR] \u2014 Karaarslan Bike",metaTitle:"Magasin de v\xE9los [SEHIR] | Karaarslan Bike",metaDescription:"Vous cherchez un magasin de v\xE9los \xE0 [SEHIR] ? Karaarslan Bike : plus de 100 v\xE9los neufs et occasion.",excerpt:"Votre magasin de v\xE9los \xE0 [SEHIR] : plus de 100 v\xE9los avec garantie.",tldr:"Karaarslan Bike : [ADRES], [PLZ] [SEHIR]. Plus de 100 v\xE9los neufs et occasion, VAE, garantie. Lun\u2013Ven 10\u201318, Sam 10\u201314.",sections:[{type:"heading",content:"Karaarslan Bike \u2014 Votre v\xE9lociste \xE0 [SEHIR]"},{type:"paragraph",content:"Karaarslan Bike est un magasin de v\xE9los \xE0 la [ADRES], [PLZ] [SEHIR]."},{type:"cta",content:"Rendez-nous visite",link:"/contact",linkText:"Itin\xE9raire & Contact"}]},tr:{title:"[SEHIR] Bisiklet\xE7i \u2014 Karaarslan Bike",metaTitle:"[SEHIR] Bisiklet D\xFCkkan\u0131 | Karaarslan Bike",metaDescription:"[SEHIR]'da bisiklet d\xFCkkan\u0131 ar\u0131yorsunuz? Karaarslan Bike: 100+ yeni ve ikinci el bisiklet, garanti, deneme s\xFCr\xFC\u015F\xFC.",excerpt:"[SEHIR]'daki bisiklet d\xFCkkan\u0131n\u0131z: Garantili 100+ yeni ve ikinci el bisiklet.",tldr:"Karaarslan Bike: [ADRES], [PLZ] [SEHIR]. 100+ yeni ve ikinci el bisiklet, e-bisiklet, garanti. Pzt\u2013Cum 10\u201318, Cmt 10\u201314. WhatsApp: [TELEFON].",sections:[{type:"heading",content:"Karaarslan Bike \u2014 [SEHIR]'daki bisiklet ma\u011Fazan\u0131z"},{type:"paragraph",content:"Karaarslan Bike, [ADRES], [PLZ] [SEHIR] adresinde bulunan bir bisiklet ma\u011Fazas\u0131d\u0131r."},{type:"cta",content:"Bizi ziyaret edin",link:"/contact",linkText:"Yol Tarifi & \u0130leti\u015Fim"}]}}},{slug:"kinderfahrrad-groesse",coverImage:"assets/blog/kinderfahrrad-groesse.jpg",date:"2026-04-12",readingTime:7,category:"ratgeber",tags:["kinderfahrrad","gr\xF6\xDFe","alter","tabelle","kinderfahrrad [SEHIR]"],relatedSlugs:["welches-fahrrad-passt-zu-mir","fahrrad-rahmengroesse-berechnen"],translations:{de:{title:"Kinderfahrrad Gr\xF6\xDFe \u2014 Welche Gr\xF6\xDFe f\xFCr welches Alter?",metaTitle:"Kinderfahrrad Gr\xF6\xDFe \u2014 Tabelle nach Alter & K\xF6rpergr\xF6\xDFe | Karaarslan Bike",metaDescription:"Welche Kinderfahrrad-Gr\xF6\xDFe passt? Gr\xF6\xDFentabelle nach Alter & K\xF6rpergr\xF6\xDFe \u2713 12 bis 26 Zoll \u2713 Tipps vom Fachh\xE4ndler aus [SEHIR].",excerpt:"Die richtige Fahrradgr\xF6\xDFe ist entscheidend f\xFCr Sicherheit und Spa\xDF. Unsere Tabelle zeigt, welches Rad zu welchem Alter passt.",tldr:"Kinderfahrr\xE4der gibt es von 12 bis 26 Zoll. Entscheidend ist die K\xF6rpergr\xF6\xDFe, nicht nur das Alter. Ab 95 cm \u2192 12 Zoll, ab 105 cm \u2192 16 Zoll, ab 120 cm \u2192 20 Zoll, ab 135 cm \u2192 24 Zoll, ab 140 cm \u2192 26 Zoll. Bei Karaarslan Bike k\xF6nnen Kinder Probe fahren.",sections:[{type:"heading",content:"Warum ist die richtige Fahrradgr\xF6\xDFe so wichtig?"},{type:"paragraph",content:"Ein zu gro\xDFes oder zu kleines Fahrrad ist nicht nur unbequem \u2014 es ist auch unsicher. Kinder, die nicht sicher mit den F\xFC\xDFen den Boden erreichen, k\xF6nnen bei Gefahrensituationen nicht richtig reagieren. Gleichzeitig f\xFChrt ein zu kleines Rad zu einer verkrampften Haltung und macht keinen Spa\xDF."},{type:"heading",content:"Gr\xF6\xDFentabelle: Kinderfahrrad nach K\xF6rpergr\xF6\xDFe"},{type:"list",items:["12 Zoll: K\xF6rpergr\xF6\xDFe 95\u2013105 cm (ca. 2\u20134 Jahre)","14 Zoll: K\xF6rpergr\xF6\xDFe 100\u2013110 cm (ca. 3\u20135 Jahre)","16 Zoll: K\xF6rpergr\xF6\xDFe 105\u2013120 cm (ca. 4\u20136 Jahre)","18 Zoll: K\xF6rpergr\xF6\xDFe 110\u2013125 cm (ca. 5\u20137 Jahre)","20 Zoll: K\xF6rpergr\xF6\xDFe 120\u2013135 cm (ca. 6\u20139 Jahre)","24 Zoll: K\xF6rpergr\xF6\xDFe 135\u2013145 cm (ca. 8\u201312 Jahre)","26 Zoll: K\xF6rpergr\xF6\xDFe ab 140 cm (ca. 10\u201314 Jahre)"]},{type:"tip",content:"Tipp: Messen Sie die Innenbeinl\xE4nge Ihres Kindes (Schrittl\xE4nge). Das Kind sollte mit beiden Fu\xDFballen den Boden ber\xFChren, wenn es auf dem Sattel sitzt."},{type:"heading",content:"Worauf beim Kinderfahrrad-Kauf achten?"},{type:"list",items:["R\xFCcktrittbremse: Bis ca. 6 Jahre empfohlen, da kleinere H\xE4nde oft nicht genug Kraft f\xFCr Handbremsen haben.","Gewicht: Ein leichtes Rad l\xE4sst sich besser kontrollieren. Faustregel: max. 30\u201340 % des K\xF6rpergewichts.","St\xFCtzr\xE4der: Von Experten nicht empfohlen \u2014 besser mit einem Laufrad starten.","Beleuchtung: Ab Teilnahme am Stra\xDFenverkehr Pflicht nach StVZO.","Schutzbleche & Kettenschutz: Sch\xFCtzen Kleidung und sorgen f\xFCr Sicherheit."]},{type:"heading",content:"Kinderfahrr\xE4der bei Karaarslan Bike"},{type:"paragraph",content:"Wir f\xFChren neue und gebrauchte Kinderfahrr\xE4der von 12 bis 26 Zoll. Jedes gebrauchte Rad wird gepr\xFCft und kommt mit 3 Monaten Garantie. Ihr Kind kann vor dem Kauf eine Probefahrt machen \u2014 so finden wir gemeinsam die perfekte Gr\xF6\xDFe."},{type:"cta",content:"Kinderfahrr\xE4der im Showroom ansehen",link:"/showroom",linkText:"Zum Showroom"}]},en:{title:"Children's Bike Size \u2014 Which Size for Which Age?",metaTitle:"Children's Bike Size Guide \u2014 Chart by Age & Height | Karaarslan Bike",metaDescription:"Which children's bike size fits? Size chart by age & height \u2713 12 to 26 inch \u2713 Expert tips from [SEHIR]'s bike shop.",excerpt:"The right bike size is crucial for safety and fun. Our chart shows which bike fits which age.",tldr:`Children's bikes range from 12 to 26 inches. Body height matters more than age. From 95 cm \u2192 12", 105 cm \u2192 16", 120 cm \u2192 20", 135 cm \u2192 24", 140 cm \u2192 26". Test rides available at Karaarslan Bike.`,sections:[{type:"heading",content:"Why is the right bike size so important?"},{type:"paragraph",content:"A bike that's too big or too small is not only uncomfortable \u2014 it's also unsafe. Children who can't safely touch the ground with their feet can't react properly in dangerous situations."},{type:"heading",content:"Size Chart: Children's Bikes by Height"},{type:"list",items:["12 inch: Height 95\u2013105 cm (approx. 2\u20134 years)","16 inch: Height 105\u2013120 cm (approx. 4\u20136 years)","20 inch: Height 120\u2013135 cm (approx. 6\u20139 years)","24 inch: Height 135\u2013145 cm (approx. 8\u201312 years)","26 inch: Height from 140 cm (approx. 10\u201314 years)"]},{type:"tip",content:"Tip: Measure your child's inseam length. The child should be able to touch the ground with both balls of their feet while sitting on the saddle."},{type:"cta",content:"Browse children's bikes in our showroom",link:"/showroom",linkText:"To Showroom"}]},fr:{title:"Taille de v\xE9lo enfant \u2014 Quelle taille pour quel \xE2ge\xA0?",metaTitle:"Taille v\xE9lo enfant \u2014 Tableau par \xE2ge & taille | Karaarslan Bike",metaDescription:"Quelle taille de v\xE9lo pour votre enfant? Tableau de tailles par \xE2ge et taille \u2713 12 \xE0 26 pouces \u2713 Conseils experts de [SEHIR].",excerpt:"La bonne taille de v\xE9lo est essentielle pour la s\xE9curit\xE9 et le plaisir. Notre tableau montre quel v\xE9lo convient \xE0 quel \xE2ge.",tldr:`Les v\xE9los enfants vont de 12 \xE0 26 pouces. La taille du corps est plus importante que l'\xE2ge. D\xE8s 95 cm \u2192 12", 105 cm \u2192 16", 120 cm \u2192 20", 135 cm \u2192 24". Essais chez Karaarslan Bike.`,sections:[{type:"heading",content:"Pourquoi la bonne taille de v\xE9lo est-elle si importante?"},{type:"paragraph",content:"Un v\xE9lo trop grand ou trop petit n'est pas seulement inconfortable \u2014 il est aussi dangereux. Les enfants qui ne peuvent pas toucher le sol ne peuvent pas r\xE9agir correctement en cas de danger."},{type:"cta",content:"Voir les v\xE9los enfants dans notre showroom",link:"/showroom",linkText:"Vers le Showroom"}]},tr:{title:"\xC7ocuk Bisikleti Beden \u2014 Hangi Ya\u015F \u0130\xE7in Hangi Beden?",metaTitle:"\xC7ocuk Bisikleti Beden Tablosu \u2014 Ya\u015F & Boya G\xF6re | Karaarslan Bike",metaDescription:"\xC7ocu\u011Funuza hangi bisiklet bedeni uyar? Ya\u015F ve boya g\xF6re beden tablosu \u2713 12'den 26 in\xE7'e \u2713 [SEHIR]'dan uzman tavsiyeleri.",excerpt:"Do\u011Fru bisiklet bedeni g\xFCvenlik ve e\u011Flence i\xE7in \xE7ok \xF6nemli. Tablomuz hangi bisikletin hangi ya\u015Fa uydu\u011Funu g\xF6sterir.",tldr:`\xC7ocuk bisikletleri 12'den 26 in\xE7'e kadar. Boy uzunlu\u011Fu ya\u015Ftan daha \xF6nemli. 95 cm \u2192 12", 105 cm \u2192 16", 120 cm \u2192 20", 135 cm \u2192 24". Karaarslan Bike'da deneme s\xFCr\xFC\u015F\xFC yap\u0131labilir.`,sections:[{type:"heading",content:"Do\u011Fru bisiklet bedeni neden bu kadar \xF6nemli?"},{type:"paragraph",content:"\xC7ok b\xFCy\xFCk veya \xE7ok k\xFC\xE7\xFCk bir bisiklet yaln\u0131zca rahats\u0131z de\u011Fil, ayn\u0131 zamanda g\xFCvensizdir. Ayaklar\u0131yla yere basamayan \xE7ocuklar tehlikeli durumlarda do\u011Fru tepki veremez."},{type:"cta",content:"Showroom'daki \xE7ocuk bisikletlerini g\xF6r\xFCnt\xFCle",link:"/showroom",linkText:"Showroom'a Git"}]}}},{slug:"fahrrad-inspektion-kosten",coverImage:"assets/blog/fahrrad-inspektion.jpg",date:"2026-04-12",readingTime:6,category:"ratgeber",tags:["fahrrad inspektion","wartung","kosten","reparatur","fahrrad check"],relatedSlugs:["gebrauchtes-fahrrad-kaufen-tipps","fahrradladen-[SEHIR]"],translations:{de:{title:"Fahrrad Inspektion \u2014 Was wird gemacht & was kostet es?",metaTitle:"Fahrrad Inspektion \u2014 Kosten, Ablauf & Checkliste | Karaarslan Bike",metaDescription:"Was kostet eine Fahrrad Inspektion? Was wird gepr\xFCft? Ablauf, Kosten (30\u201380 \u20AC) und Checkliste \u2713 Tipps vom Fahrradladen in [SEHIR].",excerpt:"Eine regelm\xE4\xDFige Inspektion h\xE4lt Ihr Fahrrad sicher und verhindert teure Reparaturen. Hier erfahren Sie, was gepr\xFCft wird und was es kostet.",tldr:"Eine Fahrrad-Inspektion kostet je nach Umfang 30\u201380 \u20AC. Gepr\xFCft werden Bremsen, Schaltung, Reifen, Kette, Lager, Beleuchtung und Speichenspannung. Empfohlen: 1\xD7 pro Jahr oder alle 2.000 km.",sections:[{type:"heading",content:"Warum ist eine Fahrrad-Inspektion wichtig?"},{type:"paragraph",content:"Verschlei\xDF an Bremsen, Kette und Reifen passiert schleichend. Wer regelm\xE4\xDFig warten l\xE4sst, f\xE4hrt sicher und vermeidet teure Folgesch\xE4den. Eine Inspektion pro Jahr reicht f\xFCr Gelegenheitsfahrer \u2014 Pendler sollten alle 6 Monate eine machen lassen."},{type:"heading",content:"Was wird bei einer Fahrrad-Inspektion gepr\xFCft?"},{type:"list",items:["Bremsen: Bremsbel\xE4ge, Bremsz\xFCge, Bremsleistung pr\xFCfen und einstellen.","Schaltung: Schaltz\xFCge, Umwerfer und Schaltwerk justieren.","Reifen: Profil, Zustand und Luftdruck kontrollieren.","Kette: Kettenverschlei\xDF messen. Ab 0,75 % L\xE4ngung \u2192 Kette tauschen.","Lager: Steuersatz, Tretlager und Naben auf Spiel pr\xFCfen.","Beleuchtung: Vorder- und R\xFCcklicht, Reflektoren (StVZO-Pflicht).","Speichen: Spannung pr\xFCfen, Achter richten.","Schrauben: Alle Verschraubungen auf festen Sitz kontrollieren."]},{type:"heading",content:"Was kostet eine Fahrrad-Inspektion?"},{type:"list",items:["Basis-Check (Bremsen + Schaltung + Luft): ca. 20\u201330 \u20AC","Standard-Inspektion (alle Komponenten): ca. 40\u201360 \u20AC","Gro\xDFe Inspektion (inkl. Reinigung + Nachfetten): ca. 60\u201380 \u20AC","E-Bike Inspektion (+ Akku & Motor-Diagnose): ca. 70\u2013100 \u20AC"]},{type:"tip",content:"Tipp: Bringen Sie Ihr Fahrrad im Fr\xFChling zur Inspektion \u2014 vor der Hauptsaison. So haben Werkst\xE4tten k\xFCrzere Wartezeiten und Ihr Rad ist rechtzeitig fit."},{type:"heading",content:"DIY-Checkliste: Das k\xF6nnen Sie selbst pr\xFCfen"},{type:"list",items:["Reifendruck: Mindestens 1\xD7 pro Monat pr\xFCfen (Angabe steht auf der Reifenflanke).","Kette \xF6len: Alle 200\u2013300 km mit speziellem Ketten\xF6l schmieren.","Bremsen testen: Vor jeder Fahrt kurz beide Bremsen pr\xFCfen.","Licht pr\xFCfen: Vor jeder Abendfahrt Vorder- und R\xFCcklicht testen.","Schrauben: Lenker, Sattel und Achsen gelegentlich nachziehen."]},{type:"cta",content:"Inspektion f\xE4llig? Kommen Sie bei Karaarslan Bike vorbei!",link:"/contact",linkText:"Kontakt & Anfahrt"}]},en:{title:"Bike Inspection \u2014 What Gets Checked & What Does It Cost?",metaTitle:"Bike Inspection \u2014 Costs, Process & Checklist | Karaarslan Bike",metaDescription:"How much does a bike inspection cost? What gets checked? Process, costs (\u20AC30\u201380), and checklist \u2713 Tips from a bike shop in [SEHIR].",excerpt:"A regular inspection keeps your bike safe and prevents expensive repairs. Learn what gets checked and what it costs.",tldr:"A bike inspection costs \u20AC30\u201380 depending on scope. Brakes, gears, tires, chain, bearings, lights and spoke tension are checked. Recommended: once a year or every 2,000 km.",sections:[{type:"heading",content:"Why is a bike inspection important?"},{type:"paragraph",content:"Wear on brakes, chain and tires happens gradually. Regular maintenance keeps you safe and prevents expensive follow-up damage. One inspection per year is enough for occasional riders \u2014 commuters should have one every 6 months."},{type:"heading",content:"What gets checked during a bike inspection?"},{type:"list",items:["Brakes: Check and adjust brake pads, cables, and performance.","Gears: Adjust cables, derailleur, and shifting.","Tires: Check tread, condition, and pressure.","Chain: Measure chain wear. Replace at 0.75% stretch.","Bearings: Check headset, bottom bracket, and hubs for play.","Lights: Front and rear lights, reflectors.","Spokes: Check tension, true wheels."]},{type:"tip",content:"Tip: Bring your bike for inspection in spring \u2014 before peak season. Workshops have shorter wait times and your bike is ready in time."},{type:"cta",content:"Need an inspection? Visit Karaarslan Bike!",link:"/contact",linkText:"Contact & Directions"}]},fr:{title:"R\xE9vision v\xE9lo \u2014 Qu'est-ce qui est v\xE9rifi\xE9 et combien \xE7a co\xFBte\xA0?",metaTitle:"R\xE9vision v\xE9lo \u2014 Co\xFBts, d\xE9roulement & checklist | Karaarslan Bike",metaDescription:"Combien co\xFBte une r\xE9vision v\xE9lo? Que v\xE9rifie-t-on? D\xE9roulement, co\xFBts (30\u201380 \u20AC) et checklist \u2713 Conseils du v\xE9lociste \xE0 [SEHIR].",excerpt:"Une r\xE9vision r\xE9guli\xE8re garde votre v\xE9lo en s\xE9curit\xE9 et \xE9vite les r\xE9parations co\xFBteuses.",tldr:"Une r\xE9vision v\xE9lo co\xFBte entre 30 et 80 \u20AC. Freins, vitesses, pneus, cha\xEEne, roulements et \xE9clairage sont v\xE9rifi\xE9s. Recommand\xE9 : 1\xD7 par an.",sections:[{type:"heading",content:"Pourquoi une r\xE9vision v\xE9lo est-elle importante\xA0?"},{type:"paragraph",content:"L'usure des freins, de la cha\xEEne et des pneus se fait progressivement. Un entretien r\xE9gulier vous garde en s\xE9curit\xE9 et \xE9vite des dommages co\xFBteux."},{type:"cta",content:"Besoin d'une r\xE9vision? Passez chez Karaarslan Bike!",link:"/contact",linkText:"Contact & Itin\xE9raire"}]},tr:{title:"Bisiklet Bak\u0131m\u0131 \u2014 Neler Kontrol Edilir & Ne Kadara Mal Olur?",metaTitle:"Bisiklet Bak\u0131m\u0131 \u2014 Maliyet, S\xFCre\xE7 & Kontrol Listesi | Karaarslan Bike",metaDescription:"Bisiklet bak\u0131m\u0131 ne kadara mal olur? Neler kontrol edilir? S\xFCre\xE7, maliyetler (30\u201380 \u20AC) ve kontrol listesi \u2713 [SEHIR] bisiklet\xE7isinden ipu\xE7lar\u0131.",excerpt:"D\xFCzenli bak\u0131m bisikletinizi g\xFCvende tutar ve pahal\u0131 tamirleri \xF6nler.",tldr:"Bisiklet bak\u0131m\u0131 30\u201380 \u20AC aras\u0131. Frenler, vitesler, lastikler, zincir, rulmanlar ve \u0131\u015F\u0131klar kontrol edilir. \xD6nerilen: y\u0131lda 1 kez veya 2.000 km'de bir.",sections:[{type:"heading",content:"Bisiklet bak\u0131m\u0131 neden bu kadar \xF6nemli?"},{type:"paragraph",content:"Fren, zincir ve lastiklerdeki a\u015F\u0131nma yava\u015F yava\u015F ger\xE7ekle\u015Fir. D\xFCzenli bak\u0131m g\xFCvenli\u011Finizi sa\u011Flar ve pahal\u0131 hasarlar\u0131 \xF6nler."},{type:"cta",content:"Bak\u0131m zaman\u0131 m\u0131? Karaarslan Bike'a gelin!",link:"/contact",linkText:"\u0130leti\u015Fim & Yol Tarifi"}]}}},{slug:"fahrrad-pendler-stadtraeder",coverImage:"assets/blog/fahrrad-pendler.jpg",date:"2026-04-12",readingTime:7,category:"ratgeber",tags:["pendler","stadtrad","cityrad","fahrrad arbeit","pendlerrad [SEHIR]"],relatedSlugs:["welches-fahrrad-passt-zu-mir","e-bike-gebraucht-kaufen"],translations:{de:{title:"Fahrrad f\xFCr Pendler \u2014 Die besten Stadtr\xE4der 2026",metaTitle:"Pendlerfahrrad \u2014 Die besten Stadtr\xE4der & Tipps | Karaarslan Bike",metaDescription:"Das beste Fahrrad f\xFCr Pendler: Citybike, Trekkingrad oder E-Bike? Vergleich, Tipps & Empfehlungen 2026 \u2713 Vom Fahrradladen in [SEHIR].",excerpt:"Wer t\xE4glich mit dem Rad zur Arbeit f\xE4hrt, braucht ein zuverl\xE4ssiges, bequemes und wartungsarmes Fahrrad. Wir zeigen die besten Optionen.",tldr:"F\xFCr Pendler empfehlen wir Citybikes (Kurzstrecke bis 5 km), Trekkingr\xE4der (5\u201315 km) oder E-Bikes (ab 10 km oder Steigungen). Wichtig: Nabenschaltung, Nabendynamo, Schutzbleche, Gep\xE4cktr\xE4ger. Bei Karaarslan Bike finden Sie gepr\xFCfte Pendlerr\xE4der ab 199 \u20AC.",sections:[{type:"heading",content:"Welches Fahrrad eignet sich zum Pendeln?"},{type:"paragraph",content:"Das ideale Pendlerfahrrad ist zuverl\xE4ssig, bequem und wartungsarm. Je nach Strecke, Gel\xE4nde und pers\xF6nlichen Vorlieben kommen unterschiedliche Radtypen in Frage:"},{type:"heading",content:"Citybike \u2014 F\xFCr kurze Strecken (bis 5 km)"},{type:"paragraph",content:"Citybikes sind kompakt, leicht und perfekt f\xFCr die Stadt. Vorteile: aufrechte Sitzposition, Nabenschaltung (wartungsarm), oft mit Licht und Schutzblechen. Ideal f\xFCr flache Strecken innerhalb der Stadt."},{type:"heading",content:"Trekkingrad \u2014 Der Allrounder (5\u201315 km)"},{type:"paragraph",content:"Das Trekkingrad ist der beliebteste Pendlertyp: stabil, komfortabel, schnell. Es kommt mit Schutzblechen, Gep\xE4cktr\xE4ger, Lichtanlage und ist ideal f\xFCr mittlere Distanzen \u2014 auch auf Schotter oder Waldwegen."},{type:"heading",content:"E-Bike \u2014 F\xFCr lange Strecken & Steigungen"},{type:"paragraph",content:"Ab 10 km Pendelstrecke oder bei Steigungen lohnt sich ein E-Bike. Sie kommen entspannt und ohne zu schwitzen an. In [SEHIR] besonders beliebt: E-Trekkingr\xE4der mit Bosch- oder Shimano-Motor."},{type:"heading",content:"Checkliste: Das muss ein gutes Pendlerrad haben"},{type:"list",items:["Nabenschaltung: Weniger Verschlei\xDF, schaltet auch im Stand.","Nabendynamo + LED-Licht: Immer helles Licht, ohne Akku-Stress.","Schutzbleche: Pflicht bei Regen und nassem Untergrund.","Gep\xE4cktr\xE4ger: F\xFCr Taschen, Korb oder Kindersitz.","Pannensichere Reifen: Z.B. Schwalbe Marathon Plus \u2014 spart Nerven.","Kettenschutz oder Riemenantrieb: Sch\xFCtzt die Kleidung.","Guter Sattel: Auf langen Strecken entscheidend f\xFCr Komfort."]},{type:"tip",content:"Tipp f\xFCr [SEHIR]: Die Stadt hat \xFCber 420 km Radwege. Mit einem guten Pendlerrad sind die meisten Arbeitswege unter 20 Minuten. Nutzen Sie auch den Fahrradparkplatz am Hauptbahnhof f\xFCr Bahn+Rad-Kombis."},{type:"heading",content:"Pendlerr\xE4der bei Karaarslan Bike"},{type:"paragraph",content:"In unserem Showroom finden Sie eine gro\xDFe Auswahl an neuen und gebrauchten Trekkingr\xE4dern, Citybikes und E-Bikes. Jedes gebrauchte Rad wird gepr\xFCft und hat 3 Monate Garantie. Lassen Sie sich beraten \u2014 wir finden das perfekte Pendlerrad f\xFCr Ihren Arbeitsweg."},{type:"cta",content:"Pendlerr\xE4der im Showroom ansehen",link:"/showroom",linkText:"Zum Showroom"}]},en:{title:"Bikes for Commuters \u2014 The Best City Bikes 2026",metaTitle:"Commuter Bike \u2014 Best City Bikes & Tips | Karaarslan Bike",metaDescription:"The best bike for commuters: City bike, trekking bike or e-bike? Comparison, tips & recommendations 2026 \u2713 From a bike shop in [SEHIR].",excerpt:"If you ride to work every day, you need a reliable, comfortable and low-maintenance bike. We show you the best options.",tldr:"For commuters we recommend: City bikes (short distances up to 5 km), trekking bikes (5\u201315 km), or e-bikes (10+ km or hills). Key features: internal gears, hub dynamo, fenders, rack. Tested commuter bikes from \u20AC199 at Karaarslan Bike.",sections:[{type:"heading",content:"Which bike is best for commuting?"},{type:"paragraph",content:"The ideal commuter bike is reliable, comfortable, and low-maintenance. Depending on distance, terrain, and personal preferences, different bike types come into question."},{type:"heading",content:"City Bike \u2014 For short distances (up to 5 km)"},{type:"paragraph",content:"City bikes are compact, light and perfect for urban riding. Benefits: upright position, internal gears (low maintenance), often with lights and fenders."},{type:"heading",content:"Trekking Bike \u2014 The all-rounder (5\u201315 km)"},{type:"paragraph",content:"The trekking bike is the most popular commuter type: stable, comfortable, fast. Comes with fenders, rack, lights \u2014 ideal for medium distances."},{type:"heading",content:"E-Bike \u2014 For long distances & hills"},{type:"paragraph",content:"From 10 km commute distance or with hills, an e-bike is worth it. You arrive relaxed and without sweating."},{type:"cta",content:"Browse commuter bikes in our showroom",link:"/showroom",linkText:"To Showroom"}]},fr:{title:"V\xE9lo pour pendulaires \u2014 Les meilleurs v\xE9los de ville 2026",metaTitle:"V\xE9lo pendulaire \u2014 Meilleurs v\xE9los de ville & conseils | Karaarslan Bike",metaDescription:"Le meilleur v\xE9lo pour pendulaires: v\xE9lo de ville, VTC ou VAE? Comparaison, conseils & recommandations 2026 \u2713 Du v\xE9lociste \xE0 [SEHIR].",excerpt:"Si vous p\xE9dalez au travail tous les jours, vous avez besoin d'un v\xE9lo fiable, confortable et facile \xE0 entretenir.",tldr:"Pour les pendulaires: v\xE9los de ville (jusqu'\xE0 5 km), VTC (5\u201315 km) ou VAE (10+ km ou c\xF4tes). Important: moyeu \xE0 vitesses int\xE9gr\xE9es, dynamo moyeu, garde-boue, porte-bagages. V\xE9los test\xE9s \xE0 partir de 199 \u20AC chez Karaarslan Bike.",sections:[{type:"heading",content:"Quel v\xE9lo pour aller au travail?"},{type:"paragraph",content:"Le v\xE9lo pendulaire id\xE9al est fiable, confortable et n\xE9cessite peu d'entretien. Selon la distance et le terrain, diff\xE9rents types de v\xE9los conviennent."},{type:"cta",content:"Voir les v\xE9los pendulaires dans notre showroom",link:"/showroom",linkText:"Vers le Showroom"}]},tr:{title:"\u0130\u015Fe Gidi\u015F \u0130\xE7in Bisiklet \u2014 2026 En \u0130yi \u015Eehir Bisikletleri",metaTitle:"\u0130\u015Fe Gidi\u015F Bisikleti \u2014 En \u0130yi \u015Eehir Bisikletleri & \u0130pu\xE7lar\u0131 | Karaarslan Bike",metaDescription:"\u0130\u015Fe gitmek i\xE7in en iyi bisiklet: \u015Eehir bisikleti, trekking bisikleti veya e-bisiklet? Kar\u015F\u0131la\u015Ft\u0131rma, ipu\xE7lar\u0131 & 2026 \xF6nerileri \u2713 [SEHIR] bisiklet\xE7isinden.",excerpt:"Her g\xFCn bisikletle i\u015Fe gidiyorsan\u0131z, g\xFCvenilir, rahat ve bak\u0131m\u0131 kolay bir bisiklete ihtiyac\u0131n\u0131z var.",tldr:"\u0130\u015Fe gidi\u015Fte \xF6nerilerimiz: \u015Eehir bisikletleri (5 km'ye kadar), trekking bisikletleri (5\u201315 km) veya e-bisikletler (10+ km veya yoku\u015Flar). \xD6nemli: i\xE7 vites, jant dinamo, \xE7amurluk, bagaj. Karaarslan Bike'da 199 \u20AC'dan itibaren test edilmi\u015F bisikletler.",sections:[{type:"heading",content:"Hangi bisiklet i\u015Fe gitmek i\xE7in en uygun?"},{type:"paragraph",content:"\u0130deal i\u015Fe gidi\u015F bisikleti g\xFCvenilir, rahat ve bak\u0131m\u0131 kolayd\u0131r. Mesafeye, araziye ve ki\u015Fisel tercihlere g\xF6re farkl\u0131 bisiklet t\xFCrleri uygundur."},{type:"cta",content:"Showroom'daki i\u015Fe gidi\u015F bisikletlerini g\xF6r\xFCnt\xFCle",link:"/showroom",linkText:"Showroom'a Git"}]}}}];export{e as a};
